<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Kanban Board</title>
  <style>
    :root {
      --bg: #f4f7fb;
      --surface: #ffffff;
      --border: #dbe3ee;
      --text: #1d2939;
      --muted: #667085;
      --accent: #4f46e5;
      --danger: #e5484d;
      --shadow: 0 8px 20px rgba(31, 41, 55, 0.08);
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      min-height: 100vh;
      font-family: Arial, Helvetica, sans-serif;
      background: var(--bg);
      color: var(--text);
    }

    .app {
      width: min(1200px, calc(100% - 32px));
      margin: 0 auto;
      padding: 36px 0 48px;
    }

    h1 {
      margin: 0 0 24px;
      font-size: 2rem;
      letter-spacing: -0.04em;
    }

    .new-task {
      display: flex;
      gap: 10px;
      margin-bottom: 24px;
    }

    #new-card {
      flex: 1;
      min-width: 0;
      border: 1px solid var(--border);
      border-radius: 10px;
      padding: 13px 14px;
      font: inherit;
      color: var(--text);
      background: var(--surface);
      outline: none;
      box-shadow: 0 2px 5px rgba(31, 41, 55, 0.03);
    }

    #new-card:focus {
      border-color: var(--accent);
      box-shadow: 0 0 0 3px rgba(79, 70, 229, 0.14);
    }

    #add-card {
      border: 0;
      border-radius: 10px;
      padding: 0 18px;
      font: inherit;
      font-weight: 700;
      color: white;
      background: var(--accent);
      cursor: pointer;
      transition: transform 0.15s ease, background 0.15s ease;
    }

    #add-card:hover {
      background: #4338ca;
    }

    #add-card:active {
      transform: translateY(1px);
    }

    .board {
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 18px;
      align-items: start;
    }

    .column {
      min-height: 430px;
      border: 1px solid var(--border);
      border-radius: 14px;
      background: #edf2f8;
      overflow: hidden;
      transition: border-color 0.15s ease, background 0.15s ease;
    }

    .column.drag-over {
      border-color: var(--accent);
      background: #e9e9ff;
    }

    .column-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 16px;
      background: rgba(255, 255, 255, 0.72);
      border-bottom: 1px solid var(--border);
    }

    .column-header h2 {
      margin: 0;
      font-size: 1rem;
    }

    .count {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      min-width: 26px;
      height: 26px;
      padding: 0 8px;
      border-radius: 999px;
      background: #dfe5ef;
      color: #475467;
      font-size: 0.82rem;
      font-weight: 700;
    }

    .card-container {
      min-height: 360px;
      padding: 12px;
    }

    .card {
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 12px;
      margin-bottom: 10px;
      padding: 14px;
      border: 1px solid #e3e8f0;
      border-radius: 10px;
      background: var(--surface);
      box-shadow: var(--shadow);
      cursor: grab;
      user-select: none;
    }

    .card:last-child {
      margin-bottom: 0;
    }

    .card:active {
      cursor: grabbing;
    }

    .card.dragging {
      opacity: 0.45;
    }

    .card-title {
      flex: 1;
      line-height: 1.4;
      overflow-wrap: anywhere;
    }

    .card-del {
      flex: 0 0 auto;
      width: 26px;
      height: 26px;
      border: 0;
      border-radius: 7px;
      color: var(--danger);
      background: #fff0f1;
      font-size: 19px;
      line-height: 1;
      cursor: pointer;
    }

    .card-del:hover {
      background: #ffdfe1;
    }

    @media (max-width: 760px) {
      .board {
        grid-template-columns: 1fr;
      }

      .column {
        min-height: 220px;
      }

      .card-container {
        min-height: 150px;
      }
    }
  </style>
</head>
<body>
  <main class="app">
    <h1>Kanban Board</h1>

    <div class="new-task">
      <input id="new-card" type="text" placeholder="Add a task..." aria-label="New task title" />
      <button id="add-card" type="button">Add Card</button>
    </div>

    <section class="board" aria-label="Kanban board">
      <section class="column" id="col-todo" aria-labelledby="todo-heading">
        <header class="column-header">
          <h2 id="todo-heading">To Do</h2>
          <span class="count">0</span>
        </header>
        <div class="card-container"></div>
      </section>

      <section class="column" id="col-doing" aria-labelledby="doing-heading">
        <header class="column-header">
          <h2 id="doing-heading">Doing</h2>
          <span class="count">0</span>
        </header>
        <div class="card-container"></div>
      </section>

      <section class="column" id="col-done" aria-labelledby="done-heading">
        <header class="column-header">
          <h2 id="done-heading">Done</h2>
          <span class="count">0</span>
        </header>
        <div class="card-container"></div>
      </section>
    </section>
  </main>

  <script>
    (function () {
      const storageKey = "kanban-board-state";
      const columns = Array.from(document.querySelectorAll(".column"));
      const input = document.getElementById("new-card");
      const addButton = document.getElementById("add-card");
      let activeCard = null;

      function makeCardId() {
        return "card-" + Date.now() + "-" + Math.random().toString(36).slice(2, 9);
      }

      function updateCounts() {
        columns.forEach(function (column) {
          const count = column.querySelector(".card-container").children.length;
          column.querySelector(".count").textContent = count;
        });
      }

      function saveBoard() {
        const cards = [];

        columns.forEach(function (column) {
          const columnId = column.id;
          column.querySelectorAll(".card").forEach(function (card) {
            cards.push({
              id: card.id,
              title: card.querySelector(".card-title").textContent,
              column: columnId
            });
          });
        });

        localStorage.setItem(storageKey, JSON.stringify(cards));
      }

      function createCard(title, id) {
        const card = document.createElement("article");
        card.className = "card";
        card.id = id || makeCardId();
        card.draggable = true;

        const titleElement = document.createElement("span");
        titleElement.className = "card-title";
        titleElement.textContent = title;

        const deleteButton = document.createElement("button");
        deleteButton.className = "card-del";
        deleteButton.type = "button";
        deleteButton.setAttribute("aria-label", "Delete " + title);
        deleteButton.textContent = "×";

        deleteButton.addEventListener("click", function (event) {
          event.stopPropagation();
          card.remove();
          updateCounts();
          saveBoard();
        });

        card.appendChild(titleElement);
        card.appendChild(deleteButton);
        return card;
      }

      function addNewCard() {
        const title = input.value.trim();

        if (!title) {
          return;
        }

        document.querySelector("#col-todo .card-container")
          .appendChild(createCard(title));

        input.value = "";
        input.focus();
        updateCounts();
        saveBoard();
      }

      function restoreBoard() {
        let savedCards = [];

        try {
          savedCards = JSON.parse(localStorage.getItem(storageKey)) || [];
        } catch (error) {
          savedCards = [];
        }

        if (!Array.isArray(savedCards)) {
          savedCards = [];
        }

        savedCards.forEach(function (savedCard) {
          const column = document.getElementById(savedCard.column);
          if (
            column &&
            typeof savedCard.title === "string" &&
            typeof savedCard.id === "string"
          ) {
            column.querySelector(".card-container")
              .appendChild(createCard(savedCard.title, savedCard.id));
          }
        });

        updateCounts();
      }

      addButton.addEventListener("click", addNewCard);

      input.addEventListener("keydown", function (event) {
        if (event.key === "Enter") {
          addNewCard();
        }
      });

      columns.forEach(function (column) {
        column.addEventListener("dragstart", function (event) {
          const card = event.target.closest(".card");
          if (!card || !column.contains(card)) {
            return;
          }

          activeCard = card;
          card.classList.add("dragging");
          event.dataTransfer.effectAllowed = "move";
          event.dataTransfer.setData("text/plain", card.id);
        });

        column.addEventListener("dragend", function (event) {
          const card = event.target.closest(".card");
          if (card) {
            card.classList.remove("dragging");
          }

          activeCard = null;
          columns.forEach(function (item) {
            item.classList.remove("drag-over");
          });
        });

        column.addEventListener("dragover", function (event) {
          event.preventDefault();
          event.dataTransfer.dropEffect = "move";
          column.classList.add("drag-over");
        });

        column.addEventListener("dragleave", function (event) {
          if (!column.contains(event.relatedTarget)) {
            column.classList.remove("drag-over");
          }
        });

        column.addEventListener("drop", function (event) {
          event.preventDefault();
          column.classList.remove("drag-over");

          const cardId = event.dataTransfer.getData("text/plain");
          const card = document.getElementById(cardId) || activeCard;

          if (card && card.classList.contains("card")) {
            column.querySelector(".card-container").appendChild(card);
            card.classList.remove("dragging");
            updateCounts();
            saveBoard();
          }
        });
      });

      restoreBoard();
    })();
  </script>
</body>
</html>
